function solve(nums: number[]): number {
    const N = nums.length;
    // Get the sorted version of nums
    const S = [...nums].sort((a, b) => a - b);
    let totalSum = 0;

    /**
     * Checks if S is a cyclic rotation of A.
     * Assumes A and S have the same length k > 0.
     */
    const isCyclicRotation = (A: number[], S: number[], k: number): boolean => {
        if (k === 0) return true;
        if (k === 1) return A[0] === S[0];

