            if (match) {
                return true;
            }
        }
        return false;
    };


    // 1. Find all divisors k of N
    const divisors: number[] = [];
    for (let k = 1; k * k <= N; k++) {
        if (N % k === 0) {
            divisors.push(k);
            if (k * k !== N) {
                divisors.push(N / k);
            }
        }
    }

    // 2. Check each divisor k
    for (const k of divisors) {
        let isSortable = true;
        const M = N / k; // Number of blocks

        for (let i = 0; i < M; i++) {
            const start = i * k;

            // Extract blocks A_i (original) and S_i (target sorted block)
            const A_i = nums.slice(start, start + k);
            const S_i = S.slice(start, start + k);

