        for (let j = 0; j < k; j++) {
            let match = true;
            // Check if B matches A shifted by j
            for (let i = 0; i < k; i++) {
                // B[i] must match A[(j + i) % k]
                if (B[i] !== A[(j + i) % k]) {
                    match = false;
                    break;
                }
